fun getLogs(): String {
    // Fetch from disk to recover post-crash logs
    appContext?.let { ctx ->
        try {
            val file = File(ctx.filesDir, "survivor_logs.txt")
            if (file.exists()) {
                return file.readText()
            }
        } catch (e: Exception) {}
    }
    // Fallback to RAM
    return synchronized(logs) {
        logs.joinToString("\n")
    }
}

